// FAZA C2 · daily heartbeat compose.
// Reads the n8n REST API for all LETTO workflows, computes recency vs each
// workflow's expected interval, formats a Slack-ready report. Inputs are
// hardcoded so this node has zero external dependencies.
//
// Expected intervals come from each workflow's scheduleTrigger config:
//   00-ERROR-HANDLER:  on-demand (no cron) — skip recency check
//   01-MIXING:         12h
//   02-PRICE-VERIFIER: 6h
//   03-NEWSLETTER:     weekly (168h)
//   04-TELEGRAM-DAILY: 24h
//   05-CJ-REFRESH:     30m before each WF01 (~12h)
//   06-SCRAPE-REFRESH: 4h

const WORKFLOWS = [
  { id: 'wjvDlFRiG9vJhjHN', name: '00-LETTO-ERROR-HANDLER',  intervalH: null },
  { id: 'CDKykLsWg6vpmM89', name: '01-LETTO-MIXING-ENGINE',  intervalH: 12 },
  { id: 'J2oO4TJoPLBkE5SH', name: '02-LETTO-PRICE-VERIFIER', intervalH: 6 },
  { id: 'WRjnjjweNV0L3V6N', name: '03-LETTO-WEEKLY-NEWSLETTER', intervalH: 168 },
  { id: 'xlGvHDQfvo8PxfiL', name: '04-LETTO-TELEGRAM-DAILY', intervalH: 24 },
  { id: 'gymciswmEryTxis4', name: '05-LETTO-CJ-REFRESH',     intervalH: 12 },
  { id: 'JfocgS4yBLph2GVH', name: '06-LETTO-SCRAPE-REFRESH', intervalH: 4 }
];

return [{ json: { workflows: WORKFLOWS, generatedAt: new Date().toISOString() } }];

// Probe each workflow's last execution via n8n REST API and compose the
// Slack heartbeat message. Uses fetch() inside a code node — simpler than
// SplitInBatches for a one-time daily summary.
//
// Status semantics:
//   ✅  fired within expected interval
//   ⚠️  fired but stale (>2× interval)
//   🔴  last execution status === 'error' OR no executions found

const WORKFLOWS = $input.all()[0].json.workflows;
const N8N_API = 'http://localhost:5678/api/v1';
const apiKey = $env.N8N_API_KEY;
const now = Date.now();

async function lastExec(id) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: N8N_API + '/executions?workflowId=' + id + '&limit=1',
      headers: { 'X-N8N-API-KEY': apiKey },
      json: true
    });
    const list = r && r.data ? r.data : [];
    return list[0] || null;
  } catch (e) {
    return { error: e.message };
  }
}

const lines = ['📊 Letto orchestra heartbeat · ' + new Date().toISOString().slice(0,10)];
let anyAlert = false;

for (const wf of WORKFLOWS) {
  const exec = await lastExec.call(this, wf.id);
  let glyph = '✅';
  let suffix = '';
  if (!exec || exec.error) {
    glyph = '🔴';
    suffix = ' · NO RECENT EXECUTIONS' + (exec && exec.error ? ' (' + exec.error + ')' : '');
    anyAlert = true;
  } else {
    const startedAt = new Date(exec.startedAt).getTime();
    const ageMs = now - startedAt;
    const ageH = Math.floor(ageMs / 3600000);
    const ageM = Math.floor((ageMs % 3600000) / 60000);
    const ageStr = ageH + 'h ' + ageM + 'm';
    if (exec.status === 'error' || exec.status === 'crashed') {
      glyph = '🔴'; suffix = ' · last status=' + exec.status + ' (' + ageStr + ' ago)';
      anyAlert = true;
    } else if (wf.intervalH && ageMs > 2 * wf.intervalH * 3600000) {
      glyph = '⚠️'; suffix = ' · stale (' + ageStr + ' ago, expected every ' + wf.intervalH + 'h)';
      anyAlert = true;
    } else {
      suffix = ' · last fired ' + ageStr + ' ago' + (wf.intervalH ? ' (' + wf.intervalH + 'h cron)' : '');
    }
  }
  lines.push(glyph + ' ' + wf.name + suffix);
}

if (!anyAlert) lines.push('\nAll greens · orchestra stable.');

return [{ json: { text: lines.join('\n'), anyAlert } }];
